const YH_UNIVERSE_REFERRAL_CACHE_KEY = 'yh_universe_referral_snapshot_v1';

function formatYHUniverseReferralMoney(amount = 0, currency = 'USD') {
    return formatYHWalletMoney(amount, currency);
}

function readYHUniverseReferralCache() {
    return readYHJsonCache(YH_UNIVERSE_REFERRAL_CACHE_KEY, null) || {};
}

function writeYHUniverseReferralCache(snapshot = {}) {
    writeYHJsonCache(YH_UNIVERSE_REFERRAL_CACHE_KEY, snapshot);
}

function normalizeYHUniverseReferralStatusLabel(value = '', rewardStatus = '') {
    const status = String(value || '').trim().toLowerCase();
    const reward = String(rewardStatus || '').trim().toLowerCase();

    if (reward === 'commission_created' || status === 'commission_earned') return 'Commission Earned';
    if (reward === 'created' || status === 'reward_created') return 'Commission Earned';
    if (status === 'qualified' || reward === 'qualified') return 'Paying Referral';
    if (status === 'rejected' || reward === 'rejected') return 'Rejected';
    if (reward === 'awaiting_payment' || status === 'pending') return 'Awaiting First Purchase';

    return status
        ? status.replace(/[_-]+/g, ' ').replace(/\b\w/g, (char) => char.toUpperCase())
        : 'Awaiting First Purchase';
}

function getYHUniverseReferralStatusTone(value = '', rewardStatus = '') {
    const status = String(value || '').trim().toLowerCase();
    const reward = String(rewardStatus || '').trim().toLowerCase();

    if (reward === 'commission_created' || status === 'commission_earned') return 'earned';
    if (reward === 'created' || status === 'reward_created') return 'earned';
    if (status === 'qualified' || reward === 'qualified') return 'qualified';
    if (status === 'rejected' || reward === 'rejected') return 'rejected';

    return 'pending';
}

function formatYHUniverseReferralDate(value = '') {
    const clean = String(value || '').trim();
    if (!clean) return 'No date yet';

    const date = new Date(clean);
    if (Number.isNaN(date.getTime())) return clean;

    return date.toLocaleDateString(undefined, {
        month: 'short',
        day: 'numeric',
        year: 'numeric'
    });
}

function getYHUniverseReferralDisplayName(item = {}) {
    const candidates = [
        item.referredName,
        item.referredUsername ? `@${String(item.referredUsername).replace(/^@+/, '')}` : '',
        item.referredEmail,
        item.referredUid
    ];

    return candidates
        .map((value) => String(value || '').trim())
        .find(Boolean) || 'Referred member';
}

function renderYHUniverseReferralList(referrals = []) {
    const listEl = document.getElementById('yh-universe-referral-list');
    if (!listEl) return;

    const items = Array.isArray(referrals) ? referrals.slice(0, 8) : [];

    if (!items.length) {
        listEl.innerHTML = `
            <div class="yh-universe-referral-empty">
                No referrals yet. Copy your link and invite your first member into YH Universe.
            </div>
        `;
        return;
    }

    listEl.innerHTML = items.map((item) => {
        const name = getYHUniverseReferralDisplayName(item);
        const statusLabel = normalizeYHUniverseReferralStatusLabel(item.status, item.rewardStatus);
        const tone = getYHUniverseReferralStatusTone(item.status, item.rewardStatus);
        const division = String(item.qualifiedDivision || '').trim();
        const rewardAmount = Number(item.commissionAmount || item.rewardAmount || 0);
        const commissionCount = Number(item.commissionCount || 0);
        const currency = String(item.currency || 'USD').trim().toUpperCase() || 'USD';
        const earned = commissionCount > 0 ||
            item.rewardStatus === 'commission_created' ||
            item.status === 'commission_earned' ||
            item.rewardStatus === 'created' ||
            item.status === 'reward_created';
        const date = item.latestCommissionAt || item.rewardCreatedAt || item.qualifiedAt || item.capturedAt;

        return `
            <article class="yh-universe-referral-item" data-referral-tone="${academyFeedEscapeHtml(tone)}">
                <div class="yh-universe-referral-avatar">${academyFeedEscapeHtml(String(name || 'Y').charAt(0).toUpperCase())}</div>

                <div class="yh-universe-referral-item-main">
                    <div class="yh-universe-referral-item-top">
                        <strong>${academyFeedEscapeHtml(name)}</strong>
                        <span class="yh-universe-referral-status" data-referral-tone="${academyFeedEscapeHtml(tone)}">
                            ${academyFeedEscapeHtml(statusLabel)}
                        </span>
                    </div>

                    <div class="yh-universe-referral-item-meta">
                        <span>${academyFeedEscapeHtml(formatYHUniverseReferralDate(date))}</span>
                        ${division ? `<span>Latest purchase: ${academyFeedEscapeHtml(division)}</span>` : `<span>Awaiting first purchase</span>`}
                        ${commissionCount > 0 ? `<span>${academyFeedEscapeHtml(String(commissionCount))} payment${commissionCount === 1 ? '' : 's'}</span>` : ''}
                        ${earned ? `<span>${academyFeedEscapeHtml(formatYHUniverseReferralMoney(rewardAmount, currency))}</span>` : ''}
                    </div>
                </div>
            </article>
        `;
    }).join('');
}

function renderYHUniverseReferralSnapshot(snapshot = {}) {
    const referral = snapshot?.referral || {};
    const stats = snapshot?.stats || {};
    const referrals = Array.isArray(snapshot?.referrals) ? snapshot.referrals : [];

    const linkEl = document.getElementById('yh-universe-referral-link');
    const codeEl = document.getElementById('yh-universe-referral-code');
    const totalEl = document.getElementById('yh-universe-referral-total');
    const qualifiedEl = document.getElementById('yh-universe-referral-qualified');
    const earnedEl = document.getElementById('yh-universe-referral-earned');

    if (linkEl) {
        linkEl.value = String(referral.link || '').trim() || 'Referral link unavailable';
    }

    if (codeEl) {
        codeEl.textContent = String(referral.code || 'Not ready').trim() || 'Not ready';
    }

    if (totalEl) {
        totalEl.textContent = String(Number(stats.total || 0));
    }

    if (qualifiedEl) {
        qualifiedEl.textContent = String(Number(stats.payingReferrals || stats.qualified || 0));
    }

    if (earnedEl) {
        earnedEl.textContent = formatYHUniverseReferralMoney(
            Number(stats.totalEarned || 0),
            stats.currency || referral.currency || 'USD'
        );
    }

    renderYHUniverseReferralList(referrals);

    safeRenderDashboardCommandOverview('data-refresh');
}

async function refreshYHUniverseReferralSnapshot(forceFresh = false) {
    if (!forceFresh) {
        const cached = readYHUniverseReferralCache();
        if (cached && typeof cached === 'object' && cached.referral) {
            renderYHUniverseReferralSnapshot(cached);
        }
    }

    const snapshot = await academyAuthedFetch('/api/universe/referrals/me', {
        method: 'GET'
    });

    if (snapshot && typeof snapshot === 'object') {
        writeYHUniverseReferralCache(snapshot);
        renderYHUniverseReferralSnapshot(snapshot);
    }

    return snapshot;
}

async function copyYHUniverseReferralLink() {
    const linkEl = document.getElementById('yh-universe-referral-link');
    const link = String(linkEl?.value || '').trim();

    if (!link || link === 'Referral link unavailable' || link === 'Loading referral link...') {
        showToast('Referral link is still loading.', 'error');
        return;
    }

    try {
        await navigator.clipboard.writeText(link);
        showToast('Universe referral link copied.', 'success');
    } catch (_) {
        try {
            linkEl?.select?.();
            document.execCommand('copy');
            showToast('Universe referral link copied.', 'success');
        } catch (error) {
            showToast('Copy failed. Select the link manually.', 'error');
        }
    }
}

function bootYHUniverseReferralPanel() {
    document.getElementById('yh-universe-referral-copy-btn')?.addEventListener('click', copyYHUniverseReferralLink);

    document.getElementById('yh-universe-referral-refresh-btn')?.addEventListener('click', () => {
        refreshYHUniverseReferralSnapshot(true)
            .then(() => showToast('Referral list refreshed.', 'success'))
            .catch((error) => {
                console.error('refreshYHUniverseReferralSnapshot error:', error);
                showToast('Unable to refresh referrals right now.', 'error');
            });
    });

    refreshYHUniverseReferralSnapshot(false).catch((error) => {
        console.error('refreshYHUniverseReferralSnapshot error:', error);
        renderYHUniverseReferralList([]);
    });
}

window.refreshYHUniverseReferralSnapshot = refreshYHUniverseReferralSnapshot;

