const YH_POST_LOGIN_DASHBOARD_BOOTSTRAP_KEY = 'yh_post_login_dashboard_bootstrap_v1';
let yhDashboardBootstrapFailSafeTimer = null;

function shouldRunPostLoginDashboardBootstrap() {
    try {
        return sessionStorage.getItem(YH_POST_LOGIN_DASHBOARD_BOOTSTRAP_KEY) === '1';
    } catch (_) {
        return false;
    }
}

function showDashboardBootstrapLoader(label = 'Checking your access...') {
    const loader = document.getElementById('yh-dashboard-bootstrap-loader');
    const text = document.getElementById('yh-dashboard-bootstrap-loader-text');

    if (text) {
        text.textContent = String(label || 'Checking your access...');
    }

    document.body?.classList.add('yh-dashboard-bootstrapping');

    if (!loader) return;

    loader.classList.remove('hidden-step');
    loader.setAttribute('aria-hidden', 'false');
}

function hideDashboardBootstrapLoader() {
    const loader = document.getElementById('yh-dashboard-bootstrap-loader');

    if (yhDashboardBootstrapFailSafeTimer) {
        clearTimeout(yhDashboardBootstrapFailSafeTimer);
        yhDashboardBootstrapFailSafeTimer = null;
    }

    try {
        sessionStorage.removeItem(YH_POST_LOGIN_DASHBOARD_BOOTSTRAP_KEY);
    } catch (_) {}

    document.body?.classList.remove('yh-dashboard-bootstrapping');

    if (!loader) return;

    loader.classList.add('hidden-step');
    loader.setAttribute('aria-hidden', 'true');
}

function scheduleDashboardBootstrapFailSafe(delayMs = 6500) {
    if (yhDashboardBootstrapFailSafeTimer) {
        clearTimeout(yhDashboardBootstrapFailSafeTimer);
    }

    yhDashboardBootstrapFailSafeTimer = setTimeout(() => {
        hideDashboardBootstrapLoader();
    }, delayMs);
}

async function hydrateDashboardTopProfile(forceFresh = false) {
    const cachedProfile = dashboardGetTopProfileCache();

    const initialName = dashboardResolveTopProfileDisplayName(
        cachedProfile,
        getStoredUserValue('yh_user_name', 'Hustler')
    );

    const initialAvatar = dashboardResolveTopProfileAvatar(
        cachedProfile,
        getStoredUserValue('yh_user_avatar', '')
    );

    updateUserProfile(initialName, initialAvatar || '');

    try {
        let result = null;

        try {
            result = await academyAuthedFetch('/api/universe/profile', {
                method: 'GET'
            });
        } catch (_) {
            result = null;
        }

        let profile =
            result?.profile && typeof result.profile === 'object'
                ? result.profile
                : null;

        if (!profile) {
            const academyResult = await academyAuthedFetch('/api/academy/profile', {
                method: 'GET'
            });

            profile =
                academyResult?.profile && typeof academyResult.profile === 'object'
                    ? academyResult.profile
                    : {};
        }

        const mergedProfile = {
            ...cachedProfile,
            ...(profile && typeof profile === 'object' ? profile : {})
        };

        const nextName = dashboardResolveTopProfileDisplayName(mergedProfile, initialName);
        const nextAvatar = dashboardResolveTopProfileAvatar(mergedProfile, initialAvatar);

        const nextCachedProfile = {
            ...cachedProfile,
            ...mergedProfile,
            display_name: nextName,
            displayName: nextName,
            fullName: mergedProfile.fullName || mergedProfile.full_name || nextName,
            avatar: nextAvatar || mergedProfile.avatar || cachedProfile.avatar || '',
            avatar_url: nextAvatar || mergedProfile.avatar_url || cachedProfile.avatar_url || '',
            avatarUrl: nextAvatar || mergedProfile.avatarUrl || cachedProfile.avatarUrl || '',
            profilePhoto: nextAvatar || mergedProfile.profilePhoto || cachedProfile.profilePhoto || '',
            photoURL: nextAvatar || mergedProfile.photoURL || cachedProfile.photoURL || '',
            updatedAt: new Date().toISOString()
        };

        dashboardPersistTopProfileCache(nextCachedProfile);
        updateUserProfile(nextName, nextAvatar || '');

        return {
            name: nextName,
            avatar: nextAvatar || ''
        };
    } catch (error) {
        console.warn('hydrateDashboardTopProfile fallback:', error);
        updateUserProfile(initialName, initialAvatar || '');

        return {
            name: initialName,
            avatar: initialAvatar || ''
        };
    }
}

function sendSystemNotification(title, text, avatarStr, color, target) {
    const notifList = document.getElementById('notif-list-container');
    const bellBadge = document.getElementById('notif-badge-count');
    if (!notifList) return;

    document.getElementById('notif-empty-state')?.remove();

    const li = document.createElement('li');
    li.className = 'unread fade-in';
    if (target) li.setAttribute('data-target', target);

    li.innerHTML = `<div class="notif-img" style="background: ${color};">${avatarStr}</div><div class="notif-text"><strong>${title}</strong> ${text}<span class="notif-time">Just now</span></div>`;

    li.addEventListener('click', () => {
        li.classList.remove('unread');

        const remainingUnread = document.querySelectorAll('#notif-dropdown .notif-list li.unread').length;
        if (bellBadge) {
            if (remainingUnread === 0) {
                bellBadge.style.display = 'none';
                bellBadge.innerText = '0';
            } else {
                bellBadge.style.display = 'flex';
                bellBadge.innerText = String(remainingUnread);
            }
        }

        closeDashboardNotificationsDropdown();

        if (target === 'announcements') document.getElementById('nav-announcements')?.click();
        else if (target === 'main-chat') document.getElementById('nav-chat')?.click();
        else if (target === 'dm') document.getElementById('btn-open-dm-modal')?.click();
        else if (target === 'profile') document.querySelector('.profile-mini')?.click();
    });

    notifList.prepend(li);

    if (bellBadge) {
        const unreadTotal = document.querySelectorAll('#notif-dropdown .notif-list li.unread').length;
        if (unreadTotal > 0) {
            bellBadge.style.display = 'flex';
            bellBadge.innerText = String(unreadTotal);
            if (bellBadge.parentElement) {
                bellBadge.parentElement.style.transform = 'scale(1.2)';
                setTimeout(() => {
                    if (bellBadge.parentElement) bellBadge.parentElement.style.transform = 'scale(1)';
                }, 200);
            }
        } else {
            bellBadge.style.display = 'none';
            bellBadge.innerText = '0';
        }
    }
}

function installDashboardProfileWholePageScrollBridge() {
    if (window.__yhDashboardProfileWholePageScrollBridgeInstalled) return;
    window.__yhDashboardProfileWholePageScrollBridgeInstalled = true;

    const getProfileHost = () => {
        const host = document.getElementById('academy-profile-view');

        if (
            !host ||
            !host.classList.contains('yh-dashboard-universe-profile-host') ||
            host.classList.contains('hidden-step')
        ) {
            return null;
        }

        return host;
    };

    const getProfileScrollTarget = () => {
        const host = getProfileHost();
        if (!host) return null;

        return host.querySelector('.yh-dashboard-universe-profile-scroll');
    };

    const shouldIgnoreWheelTarget = (target) => {
        const element = target?.nodeType === 1 ? target : target?.parentElement;
        if (!element || typeof element.closest !== 'function') return false;

        return !!element.closest(
            '.yh-dashboard-profile-modal, .yh-confirm-overlay, input, textarea, select, [contenteditable="true"]'
        );
    };

    document.addEventListener('wheel', (event) => {
        const host = getProfileHost();
        if (!host) return;
        if (!host.contains(event.target)) return;

        const scrollTarget = getProfileScrollTarget();
        if (!scrollTarget) return;

        if (scrollTarget.contains(event.target)) {
            return;
        }

        if (shouldIgnoreWheelTarget(event.target)) {
            return;
        }

        const maxScroll = scrollTarget.scrollHeight - scrollTarget.clientHeight;
        if (maxScroll <= 0) return;

        const nextScrollTop = Math.max(
            0,
            Math.min(maxScroll, scrollTarget.scrollTop + event.deltaY)
        );

        if (nextScrollTop === scrollTarget.scrollTop) return;

        event.preventDefault();
        scrollTarget.scrollTop = nextScrollTop;
    }, { passive: false });

    let touchStartY = 0;

    document.addEventListener('touchstart', (event) => {
        const host = getProfileHost();
        if (!host || !host.contains(event.target)) return;

        touchStartY = Number(event.touches?.[0]?.clientY || 0);
    }, { passive: true });

    document.addEventListener('touchmove', (event) => {
        const host = getProfileHost();
        if (!host) return;
        if (!host.contains(event.target)) return;

        const scrollTarget = getProfileScrollTarget();
        if (!scrollTarget) return;

        if (scrollTarget.contains(event.target)) {
            return;
        }

        if (shouldIgnoreWheelTarget(event.target)) {
            return;
        }

        const currentY = Number(event.touches?.[0]?.clientY || 0);
        const deltaY = touchStartY - currentY;
        touchStartY = currentY;

        const maxScroll = scrollTarget.scrollHeight - scrollTarget.clientHeight;
        if (maxScroll <= 0) return;

        const nextScrollTop = Math.max(
            0,
            Math.min(maxScroll, scrollTarget.scrollTop + deltaY)
        );

        if (nextScrollTop === scrollTarget.scrollTop) return;

        event.preventDefault();
        scrollTarget.scrollTop = nextScrollTop;
    }, { passive: false });
}

