function getDashboardPlazaInputValue(id = '') {
    return String(document.getElementById(id)?.value || '').trim();
}

function setDashboardPlazaHidden(id = '', hidden = true) {
    const node = document.getElementById(id);
    if (!node) return;
    node.hidden = Boolean(hidden);
}

function getDashboardPlazaStepNode(stepKey = '') {
    return document.querySelector(`[data-dashboard-plaza-step="${stepKey}"]`);
}

function getDashboardPlazaInputForStep(stepKey = '') {
    const map = {
        membershipType: 'plazaAppMembershipType',
        email: 'plazaAppEmail',
        fullName: 'plazaAppFullName',
        age: 'plazaAppAge',
        currentProject: 'plazaAppCurrentProject',
        resourcesNeeded: 'plazaAppResourcesNeeded',
        joinedAt: 'plazaAppJoinedAt',
        learntSoFar: 'plazaAppLearntSoFar',
        contribution: 'plazaAppContribution',
        strategicRole: 'plazaAppStrategicRole',
        strategicProof: 'plazaAppStrategicProof',
        audienceOrNetwork: 'plazaAppAudienceOrNetwork',
        capitalOrAccess: 'plazaAppCapitalOrAccess',
        highValueReason: 'plazaAppHighValueReason',
        wantsPatron: 'plazaAppWantsPatron',
        patronExpectation: 'plazaAppPatronExpectation',
        leadershipExperience: 'plazaAppLeadershipExperience',
        country: 'plazaAppCountry',
        wantsMarketplace: 'plazaAppWantsMarketplace',
        servicesProducts: 'plazaAppServicesProducts',
        referredBy: 'plazaAppReferredBy',
        howHeard: 'plazaAppHowHeard'
    };

    return document.getElementById(map[stepKey] || '');
}

function getDashboardPlazaApplicationFieldIds() {
    return [
        'plazaAppMembershipType',
        'plazaAppEmail',
        'plazaAppFullName',
        'plazaAppAge',
        'plazaAppCurrentProject',
        'plazaAppResourcesNeeded',
        'plazaAppJoinedAt',
        'plazaAppLearntSoFar',
        'plazaAppContribution',
        'plazaAppStrategicRole',
        'plazaAppStrategicProof',
        'plazaAppAudienceOrNetwork',
        'plazaAppCapitalOrAccess',
        'plazaAppHighValueReason',
        'plazaAppWantsPatron',
        'plazaAppPatronExpectation',
        'plazaAppLeadershipExperience',
        'plazaAppCountry',
        'plazaAppWantsMarketplace',
        'plazaAppServicesProducts',
        'plazaAppReferredBy',
        'plazaAppHowHeard'
    ];
}

function readDashboardPlazaApplicationDraft() {
    try {
        const parsed = JSON.parse(localStorage.getItem(DASHBOARD_PLAZA_APPLICATION_DRAFT_KEY) || 'null');

        if (!parsed || typeof parsed !== 'object') return null;
        if (parsed.schemaVersion !== DASHBOARD_PLAZA_APPLICATION_SCHEMA_VERSION) return null;

        return parsed;
    } catch (_) {
        return null;
    }
}

function writeDashboardPlazaApplicationDraft(stepKey = dashboardPlazaApplicationCurrentStep) {
    try {
        const values = {};

        getDashboardPlazaApplicationFieldIds().forEach((id) => {
            const field = document.getElementById(id);
            if (!field) return;
            values[id] = String(field.value || '').trim();
        });

        const flow = getDashboardPlazaApplicationFlow();
        const safeStep = flow.includes(stepKey)
            ? stepKey
            : flow.includes(dashboardPlazaApplicationCurrentStep)
                ? dashboardPlazaApplicationCurrentStep
                : 'membershipType';

        localStorage.setItem(DASHBOARD_PLAZA_APPLICATION_DRAFT_KEY, JSON.stringify({
            schemaVersion: DASHBOARD_PLAZA_APPLICATION_SCHEMA_VERSION,
            currentStep: safeStep,
            values,
            savedAt: new Date().toISOString()
        }));
    } catch (_) {}
}

function restoreDashboardPlazaApplicationDraft() {
    const draft = readDashboardPlazaApplicationDraft();
    if (!draft || !draft.values || typeof draft.values !== 'object') return false;

    Object.entries(draft.values).forEach(([id, value]) => {
        const field = document.getElementById(id);
        if (!field) return;
        field.value = String(value || '');
    });

    syncDashboardPlazaMembershipTypeControl();

    if (typeof syncDashboardPlazaApplicationLabels === 'function') {
        syncDashboardPlazaApplicationLabels();
    }

    const flow = getDashboardPlazaApplicationFlow();
    const draftStep = String(draft.currentStep || '').trim();
    const safeStep = flow.includes(draftStep)
        ? draftStep
        : flow[0] || 'membershipType';

    setDashboardPlazaActiveStep(safeStep);
    return true;
}

function clearDashboardPlazaApplicationDraft() {
    try {
        localStorage.removeItem(DASHBOARD_PLAZA_APPLICATION_DRAFT_KEY);
    } catch (_) {}
}

function getDashboardPlazaQuestionCopyMap() {
    const membershipType = getDashboardPlazaInputValue('plazaAppMembershipType');
    const labels = DASHBOARD_PLAZA_MEMBERSHIP_LABELS[membershipType] || DASHBOARD_PLAZA_MEMBERSHIP_LABELS.academy;

    return {
        membershipType: 'Are you a member of Young Hustlers?',
        email: 'Drop your best e-mail',
        fullName: 'Name & Surname',
        age: 'Age',
        currentProject: 'What is one project you are currently building or planning?',
        resourcesNeeded: 'What resources do you need most right now? knowledge, income, network, mentorship, etc.',
        joinedAt: labels.joined,
        learntSoFar: labels.learnt,
        contribution: labels.contribution,

        strategicRole: 'What is your strongest strategic role, status, or position?',
        strategicProof: 'What proof can you show that you are already valuable?',
        audienceOrNetwork: 'Describe your audience, network, or access.',
        capitalOrAccess: 'Do you have capital, deal flow, hiring power, distribution, or useful access?',
        highValueReason: 'Why should admin treat your application as high-value?',

        wantsPatron: 'Are you planning to become a Patrón or a Leader of the Plazas?',
        patronExpectation: 'What do you expect if you were to become a Patrón of your selected Plazas region?',
        leadershipExperience: 'Have you built, managed, or led anything before?',
        country: 'Country of Residence',
        wantsMarketplace: 'Do you provide any services/products others in the Plazas could buy, use, or request?',
        servicesProducts: 'What services/products do you provide?',
        referredBy: 'Who referred you? If nobody, leave this blank.',
        howHeard: 'If nobody referred you, how did you hear from us?'
    };
}

function syncDashboardPlazaApplicationModeCopy() {
    const modal = document.getElementById('plaza-apply-modal');
    const head = modal?.querySelector('.yh-federation-apply-head');
    if (!head) return;

    const kicker = head.querySelector('.yh-dashboard-federation-kicker');
    const title = head.querySelector('h2');
    const copy = head.querySelector('p');

    const membershipType = getDashboardPlazaInputValue('plazaAppMembershipType');
    const progressionGate = getDashboardDivisionProgressionGate('plaza', getPlazaAccessSnapshot());

    const isDirectStrategic =
        membershipType === 'direct_strategic' ||
        progressionGate.track === 'direct_strategic';

    const isAdminOverride = progressionGate.track === 'admin_override';

    if (kicker) {
        kicker.textContent = isDirectStrategic
            ? 'Plazas Strategic Review'
            : isAdminOverride
                ? 'Plazas Admin Override'
                : 'Plazas Application';
    }

    if (title) {
        title.textContent = isDirectStrategic
            ? 'Apply for Plazas Strategic Review'
            : isAdminOverride
                ? 'Apply through Admin Override'
                : 'Apply for Plazas Access';
    }

    if (copy) {
        copy.textContent = isDirectStrategic
            ? 'This route is for high-value applicants who are not moving through the normal Academy score ladder. Admin will review your proof, network, capital, access, and strategic contribution.'
            : isAdminOverride
                ? 'Admin has manually unlocked this application gate. You can submit even before reaching the normal Academy score requirement.'
                : 'The Plazas are application-gated. Submit this internal Dashboard form first. Your account stays locked until admin approves your Plazas application.';
    }
}

function syncDashboardPlazaDynamicQuestionLabels() {
    const flow = getDashboardPlazaApplicationFlow().filter((step) => step !== 'stop' && step !== 'submit');
    const copyMap = getDashboardPlazaQuestionCopyMap();

    flow.forEach((stepKey, index) => {
        const stepNode = getDashboardPlazaStepNode(stepKey);
        const labelSpan = stepNode?.querySelector('label.form-group > span');

        if (!labelSpan || !copyMap[stepKey]) return;

        labelSpan.textContent = `${index + 1}. ${copyMap[stepKey]}`;
    });
}

function syncDashboardPlazaApplicationLabels() {
    syncDashboardPlazaApplicationModeCopy();
    syncDashboardPlazaDynamicQuestionLabels();
}

function getDashboardPlazaApplicationFlow() {
    const membershipType = getDashboardPlazaInputValue('plazaAppMembershipType');
    const wantsPatron = getDashboardPlazaInputValue('plazaAppWantsPatron');
    const wantsMarketplace = getDashboardPlazaInputValue('plazaAppWantsMarketplace');
    const referredBy = getDashboardPlazaInputValue('plazaAppReferredBy');

    const flow = ['membershipType', 'email'];

    if (membershipType === 'not_yet') {
        flow.push('stop');
        return flow;
    }

    if (
        membershipType !== 'academy' &&
        membershipType !== 'federation' &&
        membershipType !== 'direct_strategic'
    ) {
        return flow;
    }

    flow.push(
        'fullName',
        'age',
        'currentProject',
        'resourcesNeeded',
        'joinedAt',
        'learntSoFar',
        'contribution'
    );

    if (membershipType === 'direct_strategic') {
        flow.push(
            'strategicRole',
            'strategicProof',
            'audienceOrNetwork',
            'capitalOrAccess',
            'highValueReason'
        );
    }

    flow.push('wantsPatron');

    if (wantsPatron === 'yes') {
        flow.push('patronExpectation', 'leadershipExperience', 'country');
    } else if (wantsPatron === 'no') {
        flow.push('country');
    } else {
        return flow;
    }

    flow.push('wantsMarketplace');

    if (wantsMarketplace === 'yes') {
        flow.push('servicesProducts', 'referredBy');
    } else if (wantsMarketplace === 'no') {
        flow.push('referredBy');
    } else {
        return flow;
    }

    if (!referredBy) {
        flow.push('howHeard');
    }

    flow.push('submit');
    return flow;
}

function syncDashboardPlazaProgress(stepKey = '') {
    const flow = getDashboardPlazaApplicationFlow().filter((step) => step !== 'stop' && step !== 'submit');
    const index = Math.max(flow.indexOf(stepKey), 0);
    const total = Math.max(flow.length, 1);
    const percent = stepKey === 'submit' ? 100 : Math.min(((index + 1) / total) * 100, 100);

    const text = document.getElementById('dashboardPlazaProgressText');
    const bar = document.getElementById('dashboardPlazaProgressBar');

    if (text) {
        text.textContent = stepKey === 'submit'
            ? 'Ready to submit'
            : `Question ${Math.min(index + 1, total)} of ${total}`;
    }

    if (bar) {
        bar.style.width = `${percent}%`;
    }
}

function setDashboardPlazaActiveStep(stepKey = 'membershipType') {
    dashboardPlazaApplicationCurrentStep = stepKey;
    syncDashboardPlazaApplicationLabels();

    const memberStepKeys = new Set([
        'fullName',
        'age',
        'currentProject',
        'resourcesNeeded',
        'joinedAt',
        'learntSoFar',
        'contribution',
        'strategicRole',
        'strategicProof',
        'audienceOrNetwork',
        'capitalOrAccess',
        'highValueReason',
        'wantsPatron',
        'patronExpectation',
        'leadershipExperience',
        'country',
        'wantsMarketplace',
        'servicesProducts',
        'referredBy',
        'howHeard',
        'submit'
    ]);

    const patronStepKeys = new Set(['patronExpectation', 'leadershipExperience']);
    const marketplaceStepKeys = new Set(['wantsMarketplace', 'servicesProducts', 'referredBy', 'howHeard']);

    setDashboardPlazaHidden('dashboardPlazaMemberFields', !memberStepKeys.has(stepKey));
    setDashboardPlazaHidden('dashboardPlazaPatronYesFields', !patronStepKeys.has(stepKey));
    setDashboardPlazaHidden('dashboardPlazaMarketplaceFields', !marketplaceStepKeys.has(stepKey));

    document.querySelectorAll('[data-dashboard-plaza-step]').forEach((node) => {
        const isActive = node.dataset.dashboardPlazaStep === stepKey;
        node.hidden = !isActive;
        node.classList.toggle('is-active', isActive);
    });

    syncDashboardPlazaProgress(stepKey);

    const input = getDashboardPlazaInputForStep(stepKey);
    if (input) {
        window.setTimeout(() => input.focus(), 60);
    }

    writeDashboardPlazaApplicationDraft(stepKey);
}

function resetDashboardPlazaApplicationFlow() {
    dashboardPlazaApplicationCurrentStep = 'membershipType';
    setDashboardPlazaActiveStep('membershipType');
}

function validateDashboardPlazaCurrentStep() {
    const stepKey = dashboardPlazaApplicationCurrentStep;

    if (stepKey === 'referredBy' || stepKey === 'stop' || stepKey === 'submit') {
        return true;
    }

    const input = getDashboardPlazaInputForStep(stepKey);
    if (!input) return true;

    const value = String(input.value || '').trim();

    if (!value) {
        showToast('Please answer this question first.', 'error');
        input.focus();
        return false;
    }

    if (stepKey === 'email' && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) {
        showToast('Please enter a valid email address.', 'error');
        input.focus();
        return false;
    }

    if (stepKey === 'age') {
        const age = Number.parseInt(value, 10);
        if (!Number.isFinite(age) || age < 13 || age > 120) {
            showToast('Please enter a valid age.', 'error');
            input.focus();
            return false;
        }
    }

    return true;
}

function goToNextDashboardPlazaStep() {
    if (!validateDashboardPlazaCurrentStep()) return;

    const flow = getDashboardPlazaApplicationFlow();
    const currentIndex = flow.indexOf(dashboardPlazaApplicationCurrentStep);
    const nextStep = flow[currentIndex + 1] || 'submit';

    syncDashboardPlazaApplicationLabels();
    setDashboardPlazaActiveStep(nextStep);
}

function buildDashboardPlazaApplicationPayload() {
    const rawMembershipType = getDashboardPlazaInputValue('plazaAppMembershipType');
    const wantsPatron = getDashboardPlazaInputValue('plazaAppWantsPatron');
    const wantsMarketplace = getDashboardPlazaInputValue('plazaAppWantsMarketplace');
    const academySeed = buildDashboardPlazaAcademySeed();
    const progressionGate = getDashboardDivisionProgressionGate('plaza', getPlazaAccessSnapshot());
    const academyProgression = progressionGate.academyProgression || getYHAcademyProgressionSnapshot();
    const forcedMembershipType = getDashboardPlazaForcedMembershipType();

    const membershipType =
        forcedMembershipType ||
        rawMembershipType ||
        (progressionGate.track === 'direct_strategic' ? 'direct_strategic' : rawMembershipType);

    return {
        schemaVersion: DASHBOARD_PLAZA_APPLICATION_SCHEMA_VERSION,
        source: 'Dashboard Plaza Application',

        applicationTrack: progressionGate.track,
        directStrategicApplicant: progressionGate.track === 'direct_strategic',
        academyUnlockRequirement: {
            division: 'plaza',
            requiredScore: progressionGate.requiredScore,
            currentScore: progressionGate.currentScore,
            unlocked: progressionGate.locked !== true,
            label: progressionGate.label,
            copy: progressionGate.copy
        },

        membershipType,
        email: getDashboardPlazaInputValue('plazaAppEmail'),

        fullName: getDashboardPlazaInputValue('plazaAppFullName'),
        age: getDashboardPlazaInputValue('plazaAppAge'),
        currentProject: getDashboardPlazaInputValue('plazaAppCurrentProject'),
        resourcesNeeded: getDashboardPlazaInputValue('plazaAppResourcesNeeded'),

        joinedAt: getDashboardPlazaInputValue('plazaAppJoinedAt'),
        learntSoFar: getDashboardPlazaInputValue('plazaAppLearntSoFar'),
        contribution: getDashboardPlazaInputValue('plazaAppContribution'),

        directStrategicProfile: {
            strategicRole: getDashboardPlazaInputValue('plazaAppStrategicRole'),
            strategicProof: getDashboardPlazaInputValue('plazaAppStrategicProof'),
            audienceOrNetwork: getDashboardPlazaInputValue('plazaAppAudienceOrNetwork'),
            capitalOrAccess: getDashboardPlazaInputValue('plazaAppCapitalOrAccess'),
            highValueReason: getDashboardPlazaInputValue('plazaAppHighValueReason')
        },

        wantsPatron,
        patronExpectation: wantsPatron === 'yes' ? getDashboardPlazaInputValue('plazaAppPatronExpectation') : '',
        leadershipExperience: wantsPatron === 'yes' ? getDashboardPlazaInputValue('plazaAppLeadershipExperience') : '',

        country: getDashboardPlazaInputValue('plazaAppCountry'),

        wantsMarketplace,
        servicesProducts: wantsMarketplace === 'yes' ? getDashboardPlazaInputValue('plazaAppServicesProducts') : '',

        referredBy: getDashboardPlazaInputValue('plazaAppReferredBy'),
        howHeard: getDashboardPlazaInputValue('plazaAppHowHeard'),

        academySignalSnapshot: {
            academyApproved: academyProgression.academyApproved === true,
            readinessScore: academySeed.readinessScore,
            readinessStatus: academySeed.readinessStatus,
            marketplaceReady: academySeed.marketplaceReady === true,

            missionCompletionRatio: academySeed.missionCompletionRatio,
            completedCount: academySeed.completedCount,
            totalCount: academySeed.totalCount,
            missionExecutionScore: academySeed.missionExecutionScore,

            roleTrack: academySeed.roleTrack,
            lookingFor: academySeed.lookingFor,
            canOffer: academySeed.canOffer,
            availability: academySeed.availability,
            workMode: academySeed.workMode,
            proofFocus: academySeed.proofFocus
        }
    };
}

async function submitDashboardPlazaApplication(event) {
    event.preventDefault();

    const form = event.currentTarget;
    const submitBtn = document.getElementById('btn-submit-plaza-application');
    const originalText = submitBtn?.textContent || 'Submit Plaza Application ➔';

    await refreshDashboardAcademyHomeSnapshot(true);

    syncDashboardPlazaMembershipTypeControl();

    const membershipType =
        getDashboardPlazaForcedMembershipType() ||
        getDashboardPlazaInputValue('plazaAppMembershipType');

    const progressionGate = getDashboardDivisionProgressionGate('plaza', getPlazaAccessSnapshot());

    if (progressionGate.locked) {
        showToast(progressionGate.copy, 'error');
        syncPlazaEntryButton(getPlazaAccessSnapshot());
        return;
    }

    if (membershipType === 'not_yet') {
        showToast('Only Academy, Federation, or direct high-value strategic applicants can apply for Plaza access.', 'error');
        return;
    }

    try {
        if (submitBtn) {
            submitBtn.disabled = true;
            submitBtn.setAttribute('aria-disabled', 'true');
            submitBtn.textContent = 'Submitting...';
        }

        const payload = buildDashboardPlazaApplicationPayload();

        const result = await academyAuthedFetch('/api/plaza/application', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(payload)
        });

        const application =
            result?.application && typeof result.application === 'object'
                ? result.application
                : payload;

        const snapshot = {
            hasApplication: true,
            canEnterPlaza: result?.canEnterPlaza === true,
            applicationStatus: normalizePlazaStatus(result?.applicationStatus || application?.status || 'Under Review'),
            application,
            member: result?.member || null
        };

        writePlazaAccessStatusCache(snapshot);
        syncPlazaEntryButton(snapshot);
        startDashboardDivisionAccessRefreshLoop();

        clearDashboardPlazaApplicationDraft();

        form.reset();
        closePlazaApplicationModal({ preserveDraft: false });

        showToast('Plaza application submitted. Admin approval is required before entry.', 'success');
    } catch (error) {
        console.error('submitDashboardPlazaApplication error:', error);

        if (isDashboardAcademyScoreLockedError(error)) {
            await refreshDashboardAcademyHomeSnapshot(true);
            syncPlazaEntryButton(getPlazaAccessSnapshot());
            showToast(
                getDashboardAcademyScoreLockedMessage(error, 'Reach the required Academy score before applying to Plaza.'),
                'error'
            );
        } else {
            showToast(error?.message || 'Failed to submit Plaza application.', 'error');
        }
    } finally {
        if (submitBtn) {
            submitBtn.disabled = false;
            submitBtn.removeAttribute('aria-disabled');
            submitBtn.textContent = originalText;
        }
    }
}

function bindDashboardPlazaApplicationFormEvents() {
    const form = document.getElementById('form-plaza-apply');
    if (!form || form.dataset.bound === 'true') return;

    form.dataset.bound = 'true';

    const modal = document.getElementById('plaza-apply-modal');
    if (modal && modal.dataset.plazaDraftOverlayBound !== 'true') {
        modal.dataset.plazaDraftOverlayBound = 'true';

        modal.addEventListener('click', (event) => {
            if (event.target === modal) {
                closePlazaApplicationModal();
            }
        });
    }

    document.getElementById('btn-close-plaza-apply')?.addEventListener('click', closePlazaApplicationModal);
    document.getElementById('btn-cancel-plaza-apply')?.addEventListener('click', closePlazaApplicationModal);

    form.querySelectorAll('[data-dashboard-plaza-next]').forEach((button) => {
        button.addEventListener('click', goToNextDashboardPlazaStep);
    });

    form.querySelectorAll('input, select, textarea').forEach((field) => {
        const persistDraft = () => {
            writeDashboardPlazaApplicationDraft(dashboardPlazaApplicationCurrentStep);
        };

        field.addEventListener('input', persistDraft);
        field.addEventListener('change', persistDraft);
    });

    form.addEventListener('keydown', (event) => {
        if (event.key !== 'Enter') return;
        if (event.target instanceof HTMLTextAreaElement) return;

        const activeStep = getDashboardPlazaStepNode(dashboardPlazaApplicationCurrentStep);
        if (!activeStep || !activeStep.contains(event.target)) return;

        event.preventDefault();
        goToNextDashboardPlazaStep();
    });

    ['plazaAppMembershipType', 'plazaAppWantsPatron', 'plazaAppWantsMarketplace', 'plazaAppReferredBy'].forEach((id) => {
        document.getElementById(id)?.addEventListener('input', () => {
            const flow = getDashboardPlazaApplicationFlow();
            if (!flow.includes(dashboardPlazaApplicationCurrentStep)) {
                setDashboardPlazaActiveStep(flow[flow.length - 1] || 'membershipType');
            }

            if (typeof syncDashboardPlazaApplicationLabels === 'function') {
                syncDashboardPlazaApplicationLabels();
            }

            if (typeof syncDashboardPlazaProgress === 'function') {
                syncDashboardPlazaProgress(dashboardPlazaApplicationCurrentStep);
            }

            writeDashboardPlazaApplicationDraft(dashboardPlazaApplicationCurrentStep);
        });
    });

    form.addEventListener('submit', submitDashboardPlazaApplication);
}

async function markPlazaTypeformSubmitted() {
    openPlazaApplicationModal();
}
async function handlePlazaGateClick(event) {
    event?.preventDefault?.();
    event?.stopPropagation?.();

    await refreshDashboardAcademyHomeSnapshot(true);

    const snapshot = await refreshPlazaAccessStatusFromBackend(true);
    const status = normalizePlazaStatus(snapshot?.applicationStatus || '');
    const progressionGate = getDashboardDivisionProgressionGate('plaza', snapshot);

    if (snapshot?.canEnterPlaza || status === 'approved') {
        redirectToPlazaPage();
        return;
    }

    if (progressionGate.locked) {
        syncPlazaEntryButton(snapshot);
        showToast(progressionGate.copy, 'error');
        return;
    }

    if (!snapshot?.hasApplication || status === 'rejected') {
        openPlazaApplicationModal();
        return;
    }

    syncPlazaEntryButton(snapshot);
    showToast('Your Plaza application is pending approval. Admin approval is required before entry.', 'error');
}
function normalizeUniverseDivision(value = 'academy') {
    const allowedDivisions = ['overview', 'academy', 'federation', 'plazas', 'resources'];
    const normalized = String(value || '').trim().toLowerCase();
    return allowedDivisions.includes(normalized) ? normalized : 'academy';
}

function openUniverseImageLightbox(src = '', alt = '') {
    const overlay = document.getElementById('yh-universe-image-lightbox');
    const image = document.getElementById('yh-universe-image-lightbox-img');
    const caption = document.getElementById('yh-universe-image-lightbox-title');

    if (!overlay || !image) return;
    if (!src) return;

    image.src = src;
    image.alt = alt || 'Full image preview';

    if (caption) {
        caption.textContent = String(alt || '').trim();
    }

    overlay.classList.remove('hidden-step');
    overlay.setAttribute('aria-hidden', 'false');
    document.body?.classList.add('yh-universe-image-lightbox-open');
}

function closeUniverseImageLightbox() {
    const overlay = document.getElementById('yh-universe-image-lightbox');
    const image = document.getElementById('yh-universe-image-lightbox-img');
    const caption = document.getElementById('yh-universe-image-lightbox-title');

    if (!overlay) return;

    overlay.classList.add('hidden-step');
    overlay.setAttribute('aria-hidden', 'true');
    document.body?.classList.remove('yh-universe-image-lightbox-open');

    if (image) {
        image.src = '';
        image.alt = '';
    }

    if (caption) {
        caption.textContent = '';
    }
}

function initUniverseImageLightbox() {
    const overlay = document.getElementById('yh-universe-image-lightbox');
    const closeBtn = document.getElementById('yh-universe-image-lightbox-close');
    const cards = Array.from(document.querySelectorAll('.yh-universe-academy-marquee-card'));

    if (!overlay || overlay.dataset.bound === 'true') return;
    overlay.dataset.bound = 'true';

    cards.forEach((card) => {
        const img = card.querySelector('img');
        const src = img?.getAttribute('src') || '';
        const alt = img?.getAttribute('alt') || 'Full image preview';

        if (!src) return;

        card.setAttribute('role', 'button');
        card.setAttribute('tabindex', '0');
        card.setAttribute('aria-label', `Open image: ${alt}`);

        card.addEventListener('click', (event) => {
            event.preventDefault();
            event.stopPropagation();
            openUniverseImageLightbox(src, alt);
        });

        card.addEventListener('keydown', (event) => {
            if (event.key !== 'Enter' && event.key !== ' ') return;
            event.preventDefault();
            openUniverseImageLightbox(src, alt);
        });
    });

    closeBtn?.addEventListener('click', () => {
        closeUniverseImageLightbox();
    });

    overlay.addEventListener('click', (event) => {
        if (event.target === overlay) {
            closeUniverseImageLightbox();
        }
    });

    document.addEventListener('keydown', (event) => {
        if (event.key === 'Escape' && !overlay.classList.contains('hidden-step')) {
            closeUniverseImageLightbox();
        }
    });
}

function syncUniverseAcademyStrip(targetDivision = 'academy') {
    const division = normalizeUniverseDivision(targetDivision);
    const academyStrip = document.getElementById('yh-universe-academy-strip');
    const plazaStrip = document.getElementById('yh-universe-plaza-strip');
    const federationStrip = document.getElementById('yh-universe-federation-strip');

    const isAcademy = division === 'academy';
    const isPlaza = division === 'plazas';
    const isFederation = division === 'federation';

    if (academyStrip) {
        academyStrip.classList.toggle('is-active', isAcademy);
        academyStrip.setAttribute('aria-hidden', isAcademy ? 'false' : 'true');
    }

    if (plazaStrip) {
        plazaStrip.classList.toggle('is-active', isPlaza);
        plazaStrip.setAttribute('aria-hidden', isPlaza ? 'false' : 'true');
    }

    if (federationStrip) {
        federationStrip.classList.toggle('is-active', isFederation);
        federationStrip.setAttribute('aria-hidden', isFederation ? 'false' : 'true');
    }
}

function syncUniverseFeaturePanel(targetDivision = 'academy') {
    const division = normalizeUniverseDivision(targetDivision);
    const copy = universeFeatureContent[division] || universeFeatureContent.academy;

    const kicker = document.getElementById('yh-universe-feature-kicker');
    const title = document.getElementById('yh-universe-feature-title');
    const desc = document.getElementById('yh-universe-feature-desc');
    const chips = document.getElementById('yh-universe-feature-chips');

    if (kicker) kicker.textContent = copy.kicker;
    if (title) title.textContent = copy.title;
    if (desc) desc.textContent = copy.desc;
    if (chips) {
        chips.innerHTML = copy.chips.map((chip) => `<span class="yh-universe-feature-chip">${chip}</span>`).join('');
    }

    syncUniverseAcademyStrip(division);
}
function syncUniverseBridgeCardVisibility(targetDivision = 'academy') {
    const division = normalizeUniverseDivision(targetDivision);
    const bridgeCard = document.getElementById('yh-econ-bridge-card');

    if (!bridgeCard) return;

    const shouldShow = division === 'academy';

    bridgeCard.classList.toggle('hidden-step', !shouldShow);
    bridgeCard.setAttribute('aria-hidden', shouldShow ? 'false' : 'true');
}
function setUniverseSlide(targetDivision = 'academy', options = {}) {
    const division = normalizeUniverseDivision(targetDivision);
    const track = document.getElementById('yh-universe-track');
    const slides = Array.from(document.querySelectorAll('.yh-universe-slide'));
    const dots = Array.from(document.querySelectorAll('.yh-universe-dot'));
    const animate = options.animate !== false;

    activeUniverseDivision = division;

    if (!track || !slides.length) {
        syncUniverseFeaturePanel(division);
        syncUniverseBridgeCardVisibility(division);
        return division;
    }

    const slideIndex = Math.max(
        0,
        slides.findIndex((slide) => slide.getAttribute('data-division') === division)
    );

    if (!animate) {
        track.classList.add('no-transition');
    }

    track.style.transform = `translateX(-${slideIndex * 100}%)`;

    slides.forEach((slide, index) => {
        const isActive = index === slideIndex;
        slide.classList.toggle('is-active', isActive);
        slide.setAttribute('aria-hidden', isActive ? 'false' : 'true');
    });

    dots.forEach((dot) => {
        dot.classList.toggle('active', dot.getAttribute('data-division') === division);
    });

    if (!animate) {
        requestAnimationFrame(() => {
            track.classList.remove('no-transition');
        });
    }

    syncUniverseFeaturePanel(division);
    syncUniverseBridgeCardVisibility(division);
    return division;
}

