let academyProfileViewState = {
    mode: 'self',
    memberId: '',
    profile: null
};

const YH_DASHBOARD_SELF_PROFILE_CACHE_KEY = 'yh_academy_profile_cache_v1';
const YH_DASHBOARD_VISITED_PROFILE_CACHE_KEY = 'yh_universe_visited_profile_cache_v1';

function dashboardGetSelfProfileCache() {
    const cached = readYHJsonCache(YH_DASHBOARD_SELF_PROFILE_CACHE_KEY, null);

    if (!cached || typeof cached !== 'object' || Array.isArray(cached)) {
        return {};
    }

    if (!dashboardCanReuseCachedProfile(cached)) {
        try {
            localStorage.removeItem(YH_DASHBOARD_SELF_PROFILE_CACHE_KEY);
            sessionStorage.removeItem(YH_DASHBOARD_SELF_PROFILE_CACHE_KEY);
        } catch (_) {}

        return {};
    }

    return cached;
}

function dashboardIsMeaningfulBadgeState(badge = {}) {
    if (!badge || typeof badge !== 'object') return false;

    const status = String(badge.status || '').trim().toLowerCase();

    return (
        badge.active === true ||
        ['active', 'verified', 'pending', 'pending_payment', 'draft', 'checkout_started'].includes(status)
    );
}

function dashboardGetProfileIdentityKey(profile = {}) {
    const safeProfile = profile && typeof profile === 'object' ? profile : {};

    return String(
        safeProfile.id ||
        safeProfile.uid ||
        safeProfile.firebaseUid ||
        safeProfile.user_id ||
        safeProfile.userId ||
        safeProfile.email ||
        ''
    ).trim().toLowerCase();
}

function dashboardGetCurrentAuthIdentityKey() {
    const authUser = getDashboardAuthUserSnapshot();

    return String(
        authUser.id ||
        authUser.uid ||
        authUser.firebaseUid ||
        authUser.email ||
        localStorage.getItem('yh_user_email') ||
        sessionStorage.getItem('yh_user_email') ||
        ''
    ).trim().toLowerCase();
}

function dashboardCanReuseCachedProfile(profile = {}) {
    const profileKey = dashboardGetProfileIdentityKey(profile);
    const authKey = dashboardGetCurrentAuthIdentityKey();

    if (!profileKey || !authKey) return false;

    return profileKey === authKey;
}

function dashboardGetPreservedVerificationBadges(nextProfile = {}) {
    const cleanProfile = nextProfile && typeof nextProfile === 'object' ? nextProfile : {};
    const badges =
        cleanProfile.verificationBadges && typeof cleanProfile.verificationBadges === 'object'
            ? cleanProfile.verificationBadges
            : {};

    const merged = {};

    ['academy', 'federation'].forEach((division) => {
        const badge = badges[division] && typeof badges[division] === 'object'
            ? badges[division]
            : null;

        if (!dashboardIsMeaningfulBadgeState(badge)) return;

        merged[division] = {
            ...badge
        };
    });

    return merged;
}

/* PATCH: Preserve self profile fallback stats during profile hydration v1 */
function dashboardMergeProfileKeepingBadges(nextProfile = {}, ...fallbackProfiles) {
    const cleanProfile = nextProfile && typeof nextProfile === 'object' ? nextProfile : {};

    const safeFallbackProfiles = fallbackProfiles
        .filter((profile) => profile && typeof profile === 'object' && !Array.isArray(profile))
        .filter((profile) => {
            const profileKey = dashboardGetProfileIdentityKey(profile);
            return !profileKey || dashboardCanReuseCachedProfile(profile);
        });

    const mergedProfile = {
        ...safeFallbackProfiles.reduce((acc, profile) => ({ ...acc, ...profile }), {}),
        ...cleanProfile
    };

    const trustedBadgeSource =
        dashboardCanReuseCachedProfile(mergedProfile)
            ? mergedProfile
            : dashboardCanReuseCachedProfile(cleanProfile)
                ? cleanProfile
                : safeFallbackProfiles.find((profile) => dashboardCanReuseCachedProfile(profile)) || {};

    return {
        ...mergedProfile,
        verificationBadges: dashboardGetPreservedVerificationBadges(trustedBadgeSource)
    };
}
/* END PATCH: Preserve self profile fallback stats during profile hydration v1 */

function dashboardResolveProfileDisplayName(profile = {}, fallback = '') {
    const cachedProfile = dashboardGetSelfProfileCache();
    const authUser = getDashboardAuthUserSnapshot();

    const candidates = [
        profile?.display_name,
        profile?.displayName,
        profile?.fullName,
        profile?.full_name,
        profile?.name,

        authUser?.display_name,
        authUser?.displayName,
        authUser?.fullName,
        authUser?.full_name,
        authUser?.name,

        cachedProfile?.display_name,
        cachedProfile?.displayName,
        cachedProfile?.fullName,
        cachedProfile?.full_name,
        cachedProfile?.name,

        localStorage.getItem('yh_user_full_name'),
        localStorage.getItem('yh_user_display_name'),
        localStorage.getItem('yh_user_name'),

        getStoredUserValue('yh_user_full_name', ''),
        getStoredUserValue('yh_user_display_name', ''),
        getStoredUserValue('yh_user_name', ''),

        authUser?.username,
        authUser?.email,

        fallback
    ];

    const resolved = candidates
        .map((value) => String(value || '').trim())
        .find((value) => value && value.toLowerCase() !== 'hustler');

    return resolved || String(fallback || '').trim() || 'Hustler';
}

function dashboardResolveProfileAvatar(profile = {}, fallback = '') {
    const cachedProfile = dashboardGetSelfProfileCache();
    const authUser = getDashboardAuthUserSnapshot();

    return normalizeAvatarUrl(
        profile?.avatar ||
        profile?.avatar_url ||
        profile?.avatarUrl ||
        profile?.profile_photo ||
        profile?.profilePhoto ||
        profile?.photo_url ||
        profile?.photoURL ||

        authUser?.avatar ||
        authUser?.avatar_url ||
        authUser?.avatarUrl ||
        authUser?.profile_photo ||
        authUser?.profilePhoto ||
        authUser?.photo_url ||
        authUser?.photoURL ||

        cachedProfile?.avatar ||
        cachedProfile?.avatar_url ||
        cachedProfile?.avatarUrl ||
        cachedProfile?.profile_photo ||
        cachedProfile?.profilePhoto ||
        cachedProfile?.photo_url ||
        cachedProfile?.photoURL ||

        localStorage.getItem('yh_user_avatar') ||
        getStoredUserValue('yh_user_avatar', '') ||
        fallback ||
        ''
    );
}

function dashboardPersistSelfProfileCache(profile = {}) {
    if (!profile || typeof profile !== 'object') return;

    const currentCache = dashboardGetSelfProfileCache();

    const mergedProfile = dashboardMergeProfileKeepingBadges(
        profile,
        currentCache,
        academyProfileViewState?.profile
    );

    const displayName = dashboardResolveProfileDisplayName(mergedProfile, '');
    const username = String(mergedProfile.username || '').replace(/^@+/, '').trim();
    const avatar = dashboardResolveProfileAvatar(mergedProfile, '');
    const coverPhoto = String(mergedProfile.cover_photo || mergedProfile.coverPhoto || '').trim();

    const authUser = getDashboardAuthUserSnapshot();

    const profileSearchTags = pickDashboardProfileTags(
        mergedProfile.search_tags,
        mergedProfile.searchTags,
        mergedProfile.tags,
        mergedProfile.signals?.tags,
        mergedProfile.signals?.search_tags,
        mergedProfile.signals?.searchTags,
        currentCache.search_tags,
        currentCache.searchTags,
        currentCache.tags,
        currentCache.signals?.tags
    );

    const profileLookingFor = Array.isArray(mergedProfile.looking_for)
        ? mergedProfile.looking_for
        : Array.isArray(mergedProfile.lookingFor)
            ? mergedProfile.lookingFor
            : Array.isArray(currentCache.looking_for)
                ? currentCache.looking_for
                : Array.isArray(currentCache.lookingFor)
                    ? currentCache.lookingFor
                    : [];

    const profileCanOffer = Array.isArray(mergedProfile.can_offer)
        ? mergedProfile.can_offer
        : Array.isArray(mergedProfile.canOffer)
            ? mergedProfile.canOffer
            : Array.isArray(currentCache.can_offer)
                ? currentCache.can_offer
                : Array.isArray(currentCache.canOffer)
                    ? currentCache.canOffer
                    : [];

    const profileRoleTrack = String(
        mergedProfile.role_track ||
        mergedProfile.roleTrack ||
        currentCache.role_track ||
        currentCache.roleTrack ||
        ''
    ).trim();

    const profileAvailability = String(
        mergedProfile.availability ||
        currentCache.availability ||
        ''
    ).trim();

    const profileWorkMode = String(
        mergedProfile.work_mode ||
        mergedProfile.workMode ||
        currentCache.work_mode ||
        currentCache.workMode ||
        ''
    ).trim();

    const profileProofFocus = String(
        mergedProfile.proof_focus ||
        mergedProfile.proofFocus ||
        currentCache.proof_focus ||
        currentCache.proofFocus ||
        ''
    ).trim();

    const profileMarketplaceReady =
        mergedProfile.marketplace_ready === true ||
        mergedProfile.marketplaceReady === true ||
        currentCache.marketplace_ready === true ||
        currentCache.marketplaceReady === true ||
        String(
            mergedProfile.marketplace_ready ||
            mergedProfile.marketplaceReady ||
            currentCache.marketplace_ready ||
            currentCache.marketplaceReady ||
            ''
        ).trim().toLowerCase() === 'yes';

    const nextProfile = {
        ...currentCache,
        ...mergedProfile,
        id: mergedProfile.id || mergedProfile.uid || mergedProfile.firebaseUid || authUser.id || authUser.firebaseUid || '',
        uid: mergedProfile.uid || mergedProfile.id || mergedProfile.firebaseUid || authUser.id || authUser.firebaseUid || '',
        firebaseUid: mergedProfile.firebaseUid || mergedProfile.uid || mergedProfile.id || authUser.firebaseUid || authUser.id || '',
        email: mergedProfile.email || authUser.email || localStorage.getItem('yh_user_email') || '',
        display_name: displayName,
        displayName,
        fullName: mergedProfile.fullName || mergedProfile.full_name || displayName,
        avatar: avatar || mergedProfile.avatar || currentCache.avatar || '',
        cover_photo: coverPhoto || mergedProfile.cover_photo || currentCache.cover_photo || '',
        coverPhoto: coverPhoto || mergedProfile.coverPhoto || currentCache.coverPhoto || '',

        search_tags: profileSearchTags,
        searchTags: profileSearchTags,
        tags: profileSearchTags,

        role_track: profileRoleTrack,
        roleTrack: profileRoleTrack,

        looking_for: profileLookingFor,
        lookingFor: profileLookingFor,

        can_offer: profileCanOffer,
        canOffer: profileCanOffer,

        availability: profileAvailability,

        work_mode: profileWorkMode,
        workMode: profileWorkMode,

        proof_focus: profileProofFocus,
        proofFocus: profileProofFocus,

        marketplace_ready: profileMarketplaceReady,
        marketplaceReady: profileMarketplaceReady,

        updatedAt: new Date().toISOString()
    };

    writeYHJsonCache(YH_DASHBOARD_SELF_PROFILE_CACHE_KEY, nextProfile);
    dashboardWriteTopProfileCache(nextProfile);

    try {
        if (displayName) {
            localStorage.setItem('yh_user_name', displayName);
            localStorage.setItem('yh_user_full_name', displayName);
            localStorage.setItem('yh_user_display_name', displayName);
        }

        if (username) {
            localStorage.setItem('yh_user_username', username);
        }

        if (avatar) {
            localStorage.setItem('yh_user_avatar', avatar);
        }

        if (nextProfile.cover_photo || nextProfile.coverPhoto) {
            localStorage.setItem('yh_user_cover_photo', nextProfile.cover_photo || nextProfile.coverPhoto);
        }
    } catch (_) {}

    syncDashboardTopProfileIdentity(nextProfile);
}

function dashboardReadVisitedProfileCacheMap() {
    const cached = readYHJsonCache(YH_DASHBOARD_VISITED_PROFILE_CACHE_KEY, null);
    return cached && typeof cached === 'object' ? cached : {};
}

function dashboardGetVisitedProfileCache(memberId = '') {
    const normalizedMemberId = normalizeAcademyFeedId(memberId);
    if (!normalizedMemberId) return null;

    const cacheMap = dashboardReadVisitedProfileCacheMap();
    const cachedProfile = cacheMap[normalizedMemberId];

    return cachedProfile && typeof cachedProfile === 'object'
        ? cachedProfile
        : null;
}

function dashboardPersistVisitedProfileCache(profile = {}) {
    const normalizedMemberId = normalizeAcademyFeedId(profile?.id || profile?.user_id || profile?.uid || '');
    if (!normalizedMemberId || !profile || typeof profile !== 'object') return;

    const cacheMap = dashboardReadVisitedProfileCacheMap();

    cacheMap[normalizedMemberId] = {
        ...profile,
        id: normalizedMemberId,
        cachedAt: new Date().toISOString()
    };

    const entries = Object.entries(cacheMap)
        .sort(([, left], [, right]) => {
            return new Date(right?.cachedAt || 0).getTime() - new Date(left?.cachedAt || 0).getTime();
        })
        .slice(0, 50);

    writeYHJsonCache(YH_DASHBOARD_VISITED_PROFILE_CACHE_KEY, Object.fromEntries(entries));
}

function buildAcademySelfProfilePayload(profile = {}) {
    const incomingProfile = profile && typeof profile === 'object' ? profile : {};
    const cachedProfile = dashboardGetSelfProfileCache();
    const mergedProfile = dashboardMergeProfileKeepingBadges(
        incomingProfile,
        cachedProfile,
        academyProfileViewState?.profile
    );

    const cachedHome = readAcademyHomeCache() || {};

    const displayName = String(
        mergedProfile.display_name ||
        mergedProfile.displayName ||
        mergedProfile.fullName ||
        mergedProfile.full_name ||
        localStorage.getItem('yh_user_name') ||
        'Hustler'
    ).trim() || 'Hustler';

    const usernameRaw =
        String(
            mergedProfile.username ||
            getStoredUserValue('yh_user_username', '') ||
            localStorage.getItem('yh_user_username') ||
            ''
        ).trim().replace(/^@+/, '') ||
        displayName.toLowerCase().replace(/\s+/g, '');

    const savedAvatar = String(
        mergedProfile.avatar ||
        mergedProfile.profilePhoto ||
        mergedProfile.photoURL ||
        getStoredUserValue('yh_user_avatar', '') ||
        localStorage.getItem('yh_user_avatar') ||
        ''
    ).trim();

    const savedCover = String(
        mergedProfile.cover_photo ||
        mergedProfile.coverPhoto ||
        getStoredUserValue('yh_user_cover_photo', '') ||
        localStorage.getItem('yh_user_cover_photo') ||
        ''
    ).trim();

    const hiddenPosts = readAcademyHiddenPostIds();

    const readinessValue =
        mergedProfile.readiness ??
        mergedProfile.readinessScore ??
        cachedHome?.roadmap?.readinessScore ??
        cachedHome?.readinessScore ??
        cachedHome?.summary?.readinessScore ??
        '—';

    const roadmapStatus =
        mergedProfile.roadmap_status ||
        mergedProfile.roadmapStatus ||
        cachedHome?.roadmap?.status ||
        cachedHome?.roadmapStatus ||
        'Not loaded';

    const progressText =
        document.getElementById('progress-text')?.innerText ||
        mergedProfile.progress ||
        '0% Daily Progress';

    const cachedPosts = readAcademyFeedCachePosts()
        .filter((post) => {
            const postName =
                String(post?.display_name || post?.fullName || post?.username || '').trim().toLowerCase();
            const postUsername = String(post?.username || '').trim().toLowerCase();

            return (
                postName === displayName.toLowerCase() ||
                postUsername === usernameRaw.toLowerCase()
            );
        })
        .sort((a, b) => {
            const left = new Date(a?.created_at || a?.createdAt || 0).getTime();
            const right = new Date(b?.created_at || b?.createdAt || 0).getTime();
            return right - left;
        });

    return {
        ...mergedProfile,
        mode: 'self',
        id:
            mergedProfile.id ||
            mergedProfile.user_id ||
            mergedProfile.uid ||
            String(getStoredUserValue('yh_user_id', '')).trim() ||
            String(getStoredUserValue('yh_user_uid', '')).trim(),
        display_name: displayName,
        displayName,
        fullName: mergedProfile.fullName || mergedProfile.full_name || displayName,
        username: usernameRaw,
        avatar: savedAvatar,
        cover_photo: savedCover,
        coverPhoto: savedCover,
        role_label: mergedProfile.role_label || mergedProfile.roleLabel || 'Academy Member',
        bio: mergedProfile.bio || 'Focused on execution, consistency, and long-term growth inside The Academy.',
        readiness: String(readinessValue),
        progress: String(progressText).replace(' Daily Progress', ''),
        roadmap_status: String(roadmapStatus),
        followers_count: mergedProfile.followers_count ?? mergedProfile.followersCount ?? '—',
        following_count: mergedProfile.following_count ?? mergedProfile.followingCount ?? '—',
        friends_count: mergedProfile.friends_count ?? mergedProfile.friend_count ?? mergedProfile.friendsCount ?? mergedProfile.friendCount ?? '—',
        post_count: Number.isFinite(Number(mergedProfile.post_count ?? mergedProfile.postCount))
            ? Number(mergedProfile.post_count ?? mergedProfile.postCount)
            : cachedPosts.length,
        hidden_count: mergedProfile.hidden_count ?? hiddenPosts.length,
        status: mergedProfile.status || 'Active',
        search_tags: Array.isArray(mergedProfile.search_tags)
            ? mergedProfile.search_tags
            : Array.isArray(mergedProfile.searchTags)
                ? mergedProfile.searchTags
                : [],
        verificationBadges: dashboardGetPreservedVerificationBadges(
            mergedProfile,
            incomingProfile,
            cachedProfile,
            academyProfileViewState?.profile
        ),
        divisions: mergedProfile.divisions && typeof mergedProfile.divisions === 'object'
            ? mergedProfile.divisions
            : {},
        membershipSummary: mergedProfile.membershipSummary || null,
        signals: mergedProfile.signals && typeof mergedProfile.signals === 'object'
            ? mergedProfile.signals
            : {},
        trustTier: mergedProfile.trustTier || '',
        activities: Array.isArray(mergedProfile.activities) ? mergedProfile.activities : [],
        snapshot: mergedProfile.snapshot || null,
        recent_posts: Array.isArray(mergedProfile.recent_posts) && mergedProfile.recent_posts.length
            ? mergedProfile.recent_posts
            : cachedPosts.slice(0, 6)
    };
}
const YH_UNIVERSE_PROFILE_DIVISION_LABELS = {
    academy: 'Academy',
    plaza: 'Plaza',
    federation: 'Federation'
};

function normalizeYHUniverseDivisionMap(divisions = {}) {
    const source = divisions && typeof divisions === 'object' ? divisions : {};

    const normalizeOne = (key) => {
        const raw = source[key] && typeof source[key] === 'object' ? source[key] : {};

        return {
            key,
            label: raw.label || YH_UNIVERSE_PROFILE_DIVISION_LABELS[key] || key,
            isMember: raw.isMember === true,
            hasApplication: raw.hasApplication === true,
            status: String(raw.status || (raw.isMember ? 'approved' : 'not_applied')).trim(),
            statusLabel: String(raw.statusLabel || (raw.isMember ? 'Approved' : 'Not Applied')).trim(),
            membershipLabel: String(raw.membershipLabel || '').trim(),
            canEnter: raw.canEnter === true || raw.isMember === true,
            profile: raw.profile && typeof raw.profile === 'object' ? raw.profile : null,
            application: raw.application && typeof raw.application === 'object' ? raw.application : null
        };
    };

    return {
        academy: normalizeOne('academy'),
        plaza: normalizeOne('plaza'),
        federation: normalizeOne('federation')
    };
}

function getYHUniverseMemberDivisionKeys(divisions = {}) {
    return Object.entries(normalizeYHUniverseDivisionMap(divisions))
        .filter(([, state]) => state.isMember === true)
        .map(([key]) => key);
}

function getYHUniverseActivityDivisionKeys(profile = {}) {
    const memberKeys = getYHUniverseMemberDivisionKeys(profile.divisions || {});
    return memberKeys.length ? memberKeys : ['academy'];
}

function getYHUniverseDivisionTone(state = {}) {
    const status = String(state.status || '').toLowerCase();

    if (state.isMember) return 'member';
    if (status === 'under_review' || status === 'pending' || status === 'screening') return 'pending';
    if (status === 'waitlisted' || status === 'shortlisted') return 'watching';
    if (status === 'rejected') return 'blocked';

    return 'locked';
}

function getYHUniverseDivisionSnapshotCopy(key = '', state = {}, profile = {}) {
    const divisionProfile = state.profile || {};

    if (key === 'academy') {
        const readiness = profile.readiness && profile.readiness !== '—'
            ? `Readiness ${profile.readiness}`
            : 'Roadmap and execution profile';

        return state.isMember
            ? readiness
            : state.statusLabel || 'Not applied';
    }

    if (key === 'plaza') {
        const focus = divisionProfile.focus || profile.signals?.availability || '';
        return state.isMember
            ? (focus || 'Networking, opportunities, and bridge visibility')
            : state.statusLabel || 'Not applied';
    }

    if (key === 'federation') {
        const role = divisionProfile.role || divisionProfile.category || '';
        return state.isMember
            ? (role || 'Strategic access and high-value network layer')
            : state.statusLabel || 'Not applied';
    }

    return state.statusLabel || 'Not applied';
}

