function getDashboardBasicAssistantIssueCategory() {
    const select = document.getElementById('yh-dashboard-basic-assistant-category');
    const value = String(select?.value || 'general').trim();
    return DASHBOARD_BASIC_ASSISTANT_ISSUE_CATEGORIES.find((item) => item.value === value)
        || DASHBOARD_BASIC_ASSISTANT_ISSUE_CATEGORIES[0];
}

function syncDashboardBasicAssistantCategoryUi() {
    const category = getDashboardBasicAssistantIssueCategory();
    const hint = document.getElementById('yh-dashboard-basic-assistant-category-hint');
    const input = document.getElementById('yh-dashboard-basic-assistant-input');
    const promptText = category.prompt || 'Describe the issue...';

    if (hint) {
        hint.textContent = category.hint || '';
    }

    if (input) {
        input.placeholder = promptText;
        input.title = promptText;
        input.setAttribute('aria-label', promptText);
    }
}

function formatDashboardBasicAssistantTicketMessage(message = '', category = null) {
    const cleanMessage = String(message || '').trim();
    const safeCategory = category || getDashboardBasicAssistantIssueCategory();

    if (!cleanMessage) return '';

    return [
        `Issue Category: ${safeCategory.label}`,
        `Issue Details: ${cleanMessage}`
    ].join('\n');
}

const YH_DASHBOARD_AI_CHATBOT_ROBOT_AVATAR_SRC = '/assets/yh-ai-robot-avatar.png?v=20260529-ai-robot-avatar-v1';

function getDashboardAiChatbotRobotAvatarHtml(extraClass = '') {
    const className = String(extraClass || 'yh-ai-chatbot-robot-img').trim();

    return `
        <img
            src="${academyFeedEscapeHtml(YH_DASHBOARD_AI_CHATBOT_ROBOT_AVATAR_SRC)}"
            alt="YH Assistant"
            class="${academyFeedEscapeHtml(className)}"
            loading="lazy"
            decoding="async"
        >
    `;
}

function renderDashboardBasicAssistantMessages(messages = []) {
    const list = document.getElementById('yh-dashboard-basic-assistant-messages');
    if (!list) return;

    const cleanMessages = Array.isArray(messages) ? messages : [];

    if (!cleanMessages.length) {
        list.innerHTML = `
            <div class="yh-dashboard-basic-assistant-empty">
                Ask a basic question about your dashboard, profile, access, applications, or a bug you want to report.
            </div>
        `;
        return;
    }

    list.innerHTML = cleanMessages
        .map((message) => {
            const role = String(message?.role || '').trim().toLowerCase() === 'user' ? 'user' : 'assistant';
            const label = role === 'user' ? 'You' : 'YH Assistant';
            const text = academyFeedEscapeHtml(message?.text || message?.content || '');

            const assistantAvatar = role === 'assistant'
                ? `<div class="yh-dashboard-basic-assistant-message-avatar has-ai-robot-image">${getDashboardAiChatbotRobotAvatarHtml('yh-dashboard-basic-assistant-message-avatar-img')}</div>`
                : '';

            return `
                <div class="yh-dashboard-basic-assistant-message is-${role}">
                    ${assistantAvatar}
                    <div class="yh-dashboard-basic-assistant-message-main">
                        <div class="yh-dashboard-basic-assistant-message-label">${label}</div>
                        <div class="yh-dashboard-basic-assistant-message-bubble">${text.replace(/\n/g, '<br>')}</div>
                    </div>
                </div>
            `;
        })
        .join('');

    list.scrollTop = list.scrollHeight;
}

async function loadDashboardBasicAssistantMessages() {
    const list = document.getElementById('yh-dashboard-basic-assistant-messages');
    if (list) {
        list.innerHTML = `<div class="yh-dashboard-basic-assistant-empty">Loading assistant...</div>`;
    }

    const result = await academyAuthedFetch(
        `/api/dashboard/assistant/messages?conversationId=${encodeURIComponent(YH_DASHBOARD_BASIC_ASSISTANT_CONVERSATION_ID)}`,
        { method: 'GET' }
    );

    const messages = Array.isArray(result?.messages) ? result.messages : [];

    if (!messages.length) {
        renderDashboardBasicAssistantMessages([
            {
                role: 'assistant',
                text: YH_DASHBOARD_BASIC_ASSISTANT_WELCOME_MESSAGE,
                createdAt: new Date().toISOString()
            }
        ]);

        return [];
    }

    renderDashboardBasicAssistantMessages(messages);
    return messages;
}

function ensureDashboardBasicAssistantPanel() {
    let panel = document.getElementById('yh-dashboard-basic-assistant-panel');
    if (panel) return panel;

    panel = document.createElement('div');
    panel.id = 'yh-dashboard-basic-assistant-panel';
    panel.className = 'yh-dashboard-basic-assistant hidden-step';
    panel.setAttribute('role', 'dialog');
    panel.setAttribute('aria-modal', 'false');
    panel.setAttribute('aria-labelledby', 'yh-dashboard-basic-assistant-title');

    panel.innerHTML = `
        <div class="yh-dashboard-basic-assistant-card">
            <div class="yh-dashboard-basic-assistant-head">
                <div class="yh-dashboard-basic-assistant-title-row">
                    <div class="yh-dashboard-basic-assistant-avatar has-ai-robot-image">
                        ${getDashboardAiChatbotRobotAvatarHtml('yh-dashboard-basic-assistant-avatar-img')}
                    </div>

                    <div>
                        <div class="yh-dashboard-basic-assistant-kicker">Support Ticket</div>
                        <h3 id="yh-dashboard-basic-assistant-title">YH Dashboard Assistant</h3>
                        <p>Choose a category, then explain the issue so support can understand it faster.</p>
                    </div>
                </div>

                <button type="button" class="yh-dashboard-basic-assistant-close" id="yh-dashboard-basic-assistant-close" aria-label="Close assistant">✕</button>
            </div>

            <div class="yh-dashboard-basic-assistant-intake">
                <label for="yh-dashboard-basic-assistant-category">What is your issue?</label>
                <select id="yh-dashboard-basic-assistant-category" class="input-field">
                    ${DASHBOARD_BASIC_ASSISTANT_ISSUE_CATEGORIES.map((category) => `
                        <option value="${academyFeedEscapeHtml(category.value)}">${academyFeedEscapeHtml(category.label)}</option>
                    `).join('')}
                </select>
                <div id="yh-dashboard-basic-assistant-category-hint" class="yh-dashboard-basic-assistant-category-hint"></div>

                <div class="yh-dashboard-basic-assistant-category-chips" aria-label="Common issue categories">
                    <button type="button" data-dashboard-ticket-category="platform_guide">Platform Guide</button>
                    <button type="button" data-dashboard-ticket-category="earning_paths">Earning</button>
                    <button type="button" data-dashboard-ticket-category="billing">Billing</button>
                    <button type="button" data-dashboard-ticket-category="academy">Academy</button>
                    <button type="button" data-dashboard-ticket-category="federation">Federation</button>
                    <button type="button" data-dashboard-ticket-category="plazas">Plazas</button>
                    <button type="button" data-dashboard-ticket-category="technical_bug">Bug</button>
                </div>
            </div>

            <div class="yh-dashboard-basic-assistant-messages hide-scrollbar" id="yh-dashboard-basic-assistant-messages"></div>

            <form class="yh-dashboard-basic-assistant-form" id="yh-dashboard-basic-assistant-form">
                <textarea
                    id="yh-dashboard-basic-assistant-input"
                    class="input-field"
                    placeholder="Describe the issue..."
                    autocomplete="off"
                    rows="2"
                ></textarea>
                <button type="submit" class="btn-primary" id="yh-dashboard-basic-assistant-send">Send</button>
            </form>
        </div>
    `;

    document.body.appendChild(panel);

    document.getElementById('yh-dashboard-basic-assistant-close')?.addEventListener('click', () => {
        closeDashboardBasicAssistantPanel();
    });

    document.getElementById('yh-dashboard-basic-assistant-category')?.addEventListener('change', syncDashboardBasicAssistantCategoryUi);

    panel.querySelectorAll('[data-dashboard-ticket-category]').forEach((button) => {
        button.addEventListener('click', () => {
            const categoryValue = button.getAttribute('data-dashboard-ticket-category') || 'general';
            const select = document.getElementById('yh-dashboard-basic-assistant-category');

            if (select) {
                select.value = categoryValue;
            }

            syncDashboardBasicAssistantCategoryUi();
            document.getElementById('yh-dashboard-basic-assistant-input')?.focus();
        });
    });

    document.getElementById('yh-dashboard-basic-assistant-form')?.addEventListener('submit', (event) => {
        event.preventDefault();
        sendDashboardBasicAssistantMessage().catch((error) => {
            showToast(error?.message || 'Failed to send assistant message.', 'error');
        });
    });

    document.getElementById('yh-dashboard-basic-assistant-input')?.addEventListener('keydown', (event) => {
        if (event.key !== 'Enter' || event.shiftKey) return;

        event.preventDefault();
        document.getElementById('yh-dashboard-basic-assistant-form')?.requestSubmit?.();
    });

    syncDashboardBasicAssistantCategoryUi();

    return panel;
}

async function openDashboardBasicAssistantPanel() {
    const panel = ensureDashboardBasicAssistantPanel();

    panel.classList.remove('hidden-step');

    try {
        await loadDashboardBasicAssistantMessages();
    } catch (error) {
        renderDashboardBasicAssistantMessages([
            {
                role: 'assistant',
                text: error?.message || 'Assistant history could not be loaded. You can still try sending a message.'
            }
        ]);
    }

    document.getElementById('yh-dashboard-basic-assistant-input')?.focus();
}

function closeDashboardBasicAssistantPanel() {
    document.getElementById('yh-dashboard-basic-assistant-panel')?.classList.add('hidden-step');
}

async function sendDashboardBasicAssistantMessage() {
    const input = document.getElementById('yh-dashboard-basic-assistant-input');
    const sendBtn = document.getElementById('yh-dashboard-basic-assistant-send');
    const rawText = String(input?.value || '');
    const text = rawText.trim();
    const issueCategory = getDashboardBasicAssistantIssueCategory();
    const ticketMessage = formatDashboardBasicAssistantTicketMessage(text, issueCategory);

    if (!ticketMessage) return;

    if (input) input.value = '';
    if (sendBtn) sendBtn.disabled = true;
    if (input) input.disabled = true;

    const existingMessages = await loadDashboardBasicAssistantMessages().catch(() => []);

    renderDashboardBasicAssistantMessages([
        ...existingMessages,
        {
            role: 'user',
            text: ticketMessage,
            createdAt: new Date().toISOString()
        },
        {
            role: 'assistant',
            text: 'Thinking...',
            createdAt: new Date().toISOString()
        }
    ]);

    try {
        const result = await academyAuthedFetch('/api/dashboard/assistant/chat', {
            method: 'POST',
            body: JSON.stringify({
                conversationId: YH_DASHBOARD_BASIC_ASSISTANT_CONVERSATION_ID,
                message: ticketMessage,
                issueCategory: issueCategory.value,
                issueCategoryLabel: issueCategory.label,
                contextHint: `dashboard_ticket:${issueCategory.value}`
            })
        });

        const refreshedMessages = await loadDashboardBasicAssistantMessages().catch(() => []);

        if (!refreshedMessages.length && result?.reply) {
            renderDashboardBasicAssistantMessages([
                {
                    role: 'user',
                    text: ticketMessage,
                    createdAt: new Date().toISOString()
                },
                {
                    role: 'assistant',
                    text: result.reply,
                    createdAt: new Date().toISOString()
                }
            ]);
        }
    } catch (error) {
        renderDashboardBasicAssistantMessages([
            ...existingMessages,
            {
                role: 'user',
                text: ticketMessage,
                createdAt: new Date().toISOString()
            },
            {
                role: 'assistant',
                text: error?.message || 'I could not send that message. Please try again.',
                createdAt: new Date().toISOString()
            }
        ]);

        throw error;
    } finally {
        if (sendBtn) sendBtn.disabled = false;
        if (input) input.disabled = false;
        input?.focus();
    }
}

