var academyMembershipLastNotifiedStatus = '';
var academyMembershipLastFetchAt = 0;
var ACADEMY_MEMBERSHIP_POLL_MS = 60000;
var ACADEMY_MEMBERSHIP_MIN_REFRESH_GAP_MS = 30000;

